def is_checklist(title, desc):
    title_low = title.lower()
    text = (title + " " + desc).lower()
    # Strong, explicit playbook signals in TITLE — these are clearly actionable material
    title_strong = [
        "checklist", "check-list", "spreadsheet", "recipe", "bible",
        "playbook", "swipe file", "scripts", "script", "formulas",
        "templates", "template",
    ]
    for kw in title_strong:
        if kw in title_low:
            # avoid false positive: single-word "script" used as a noun for a code tool
            if kw == "script" and title_low.strip() == "script":
                continue
            return True
    # Description-based strong signals (spreadsheet/recipe book/bible/checklist mentioned)
    for kw in ["spreadsheet", "recipe book", "bible", "checklist", "playbook"]:
        if kw in text:
            return True
    return False
